using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using collectiblesManagementSystem.Models;

namespace collectiblesManagementSystem.Views;

public partial class CollectionPage : ContentPage
{
    private Models.Collection _collection;

    public CollectionPage(Models.Collection collection)
    {
        InitializeComponent();
        _collection = collection;
        Title = _collection.Name;
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();
        RefreshData();
    }

    private void RefreshData()
    {
        var sortedItems = _collection.Items
            .OrderBy(i => i.Status == ItemStatus.Sold ? 1 : 0)
            .ThenBy(i => i.Name)
            .ToList();

        ItemsList.ItemsSource = null;
        ItemsList.ItemsSource = sortedItems;

        int total = _collection.Items.Count;
        int sold = _collection.Items.Count(i => i.Status == ItemStatus.Sold);
        int toSell = _collection.Items.Count(i => i.Status == ItemStatus.ForSale);

        SummaryLabel.Text = $"Posiadane: {total} | Na sprzedaż: {toSell} | Sprzedane: {sold}";
    }

    private async void OnAddItemClicked(object sender, EventArgs e)
    {
        await Navigation.PushAsync(new ItemEditPage(_collection));
    }

    private async void OnAddColumnClicked(object sender, EventArgs e)
    {
        string columnName = await DisplayPromptAsync("Nowa Kolumna", "Podaj nazwę nowej kolumny (np. Autor, Wydanie):");
        if (!string.IsNullOrWhiteSpace(columnName) && !_collection.CustomColumns.Contains(columnName))
        {
            _collection.CustomColumns.Add(columnName);
            App.SaveData();
            await DisplayAlert("Sukces", $"Dodano kolumnę: {columnName}. Będzie dostępna przy edycji przedmiotów.", "OK");
        }
    }

    private async void OnSyncClicked(object sender, EventArgs e)
    {
        var action = await DisplayActionSheet("Import / Eksport", "Anuluj", null, "Eksportuj Kolekcję", "Importuj i Połącz");

        if (action == "Eksportuj Kolekcję")
        {
            try
            {
                var fileName = $"eksport_{_collection.Name.Replace(" ", "_")}.txt";
                var filePath = System.IO.Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), fileName);

                var serialized = _collection.Serialize();
                System.IO.File.WriteAllText(filePath, serialized);

                await DisplayAlert("Eksport Zakończony", $"Plik zapisano bezpośrednio w:\n{filePath}", "OK");
            }
            catch (Exception ex)
            {
                await DisplayAlert("Błąd", $"Nie udało się wyeksportować: {ex.Message}", "OK");
            }
        }
        else if (action == "Importuj i Połącz")
        {
            // Odklejamy się całkowicie od metody obsługującej ActionSheet, żeby uniknąć deadlocka systemowego macOS
            Dispatcher.Dispatch(async () =>
            {
                try
                {
                    // Puszczamy czysty PickAsync bez psujących się na Macu filtrów rozszerzeń (UTI)
                    var result = await FilePicker.Default.PickAsync(new PickOptions
                    {
                        PickerTitle = "Wybierz plik txt z kolekcją"
                    });

                    if (result != null)
                    {
                        if (!result.FileName.EndsWith(".txt", StringComparison.OrdinalIgnoreCase))
                        {
                            await DisplayAlert("Błąd", "Proszę wybrać poprawny plik tekstowy (.txt)", "OK");
                            return;
                        }

                        using var stream = await result.OpenReadAsync();
                        using var reader = new System.IO.StreamReader(stream);
                        string text = await reader.ReadToEndAsync();

                        var imported = Models.Collection.Deserialize(text);

                        foreach (var col in imported.CustomColumns)
                        {
                            if (!_collection.CustomColumns.Contains(col))
                                _collection.CustomColumns.Add(col);
                        }

                        foreach (var item in imported.Items)
                        {
                            if (!_collection.Items.Any(i => i.Id == item.Id))
                            {
                                _collection.Items.Add(item);
                            }
                        }

                        App.SaveData();
                        RefreshData();
                        await DisplayAlert("Sukces", "Dane zostały zaimportowane i połączone.", "OK");
                    }
                }
                catch (Exception ex)
                {
                    await DisplayAlert("Błąd", $"Nie udało się zaimportować: {ex.Message}", "OK");
                }
            });
        }
    }

    private async void OnItemSelected(object sender, SelectionChangedEventArgs e)
    {
        if (e.CurrentSelection.FirstOrDefault() is CollectionItem selectedItem)
        {
            ItemsList.SelectedItem = null;
            await Navigation.PushAsync(new ItemEditPage(_collection, selectedItem));
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using collectiblesManagementSystem.Models;

namespace collectiblesManagementSystem.Views;

public partial class CollectionPage : ContentPage
{
    private Models.Collection _collection;

    public CollectionPage(Models.Collection collection)
    {
        InitializeComponent();
        _collection = collection;
        Title = _collection.Name;
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();
        RefreshData();
    }

    private void RefreshData()
    {
        var sortedItems = _collection.Items
            .OrderBy(i => i.Status == ItemStatus.Sold ? 1 : 0)
            .ThenBy(i => i.Name)
            .ToList();

        ItemsList.ItemsSource = null;
        ItemsList.ItemsSource = sortedItems;

        int total = _collection.Items.Count;
        int sold = _collection.Items.Count(i => i.Status == ItemStatus.Sold);
        int toSell = _collection.Items.Count(i => i.Status == ItemStatus.ForSale);

        SummaryLabel.Text = $"Posiadane: {total} | Na sprzedaż: {toSell} | Sprzedane: {sold}";
    }

    private async void OnAddItemClicked(object sender, EventArgs e)
    {
        await Navigation.PushAsync(new ItemEditPage(_collection));
    }

    private async void OnAddColumnClicked(object sender, EventArgs e)
    {
        string columnName = await DisplayPromptAsync("Nowa Kolumna", "Podaj nazwę nowej kolumny (np. Autor, Wydanie):");
        if (!string.IsNullOrWhiteSpace(columnName) && !_collection.CustomColumns.Contains(columnName))
        {
            _collection.CustomColumns.Add(columnName);
            App.SaveData();
            await DisplayAlert("Sukces", $"Dodano kolumnę: {columnName}. Będzie dostępna przy edycji przedmiotów.", "OK");
        }
    }

    private async void OnSyncClicked(object sender, EventArgs e)
    {
        var action = await DisplayActionSheet("Import / Eksport", "Anuluj", null, "Eksportuj Kolekcję", "Importuj i Połącz");

        if (action == "Eksportuj Kolekcję")
        {
            try
            {
                var fileName = $"eksport_{_collection.Name.Replace(" ", "_")}.txt";
                var filePath = System.IO.Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), fileName);

                var serialized = _collection.Serialize();
                System.IO.File.WriteAllText(filePath, serialized);

                await DisplayAlert("Eksport Zakończony", $"Plik zapisano bezpośrednio w:\n{filePath}", "OK");
            }
            catch (Exception ex)
            {
                await DisplayAlert("Błąd", $"Nie udało się wyeksportować: {ex.Message}", "OK");
            }
        }
        else if (action == "Importuj i Połącz")
        {
            try
            {
#if MACCATALYST || IOS
                // Natywne rozwiązanie Apple omijające zepsuty w MAUI FilePicker
                var documentPicker = new UIKit.UIDocumentPickerViewController(new string[] { "public.text", "public.plain-text", "public.data" }, UIKit.UIDocumentPickerMode.Import);

                documentPicker.DidPickDocumentAtUrls += (sender, args) =>
                {
                    try
                    {
                        var url = args.Urls.FirstOrDefault();
                        if (url != null)
                        {
                            string text = System.IO.File.ReadAllText(url.Path);

                            MainThread.BeginInvokeOnMainThread(() => 
                            {
                                var imported = Models.Collection.Deserialize(text);

                                foreach (var col in imported.CustomColumns)
                                {
                                    if (!_collection.CustomColumns.Contains(col))
                                        _collection.CustomColumns.Add(col);
                                }

                                foreach (var item in imported.Items)
                                {
                                    if (!_collection.Items.Any(i => i.Id == item.Id))
                                        _collection.Items.Add(item);
                                }

                                App.SaveData();
                                RefreshData();
                                DisplayAlert("Sukces", "Dane zostały zaimportowane i połączone.", "OK");
                            });
                        }
                    }
                    catch (Exception ex)
                    {
                        MainThread.BeginInvokeOnMainThread(() => DisplayAlert("Błąd", $"Import plików: {ex.Message}", "OK"));
                    }
                };

                var currentViewController = Platform.GetCurrentUIViewController();
                currentViewController?.PresentViewController(documentPicker, true, null);
#else
                var result = await FilePicker.Default.PickAsync(new PickOptions { PickerTitle = "Wybierz plik z kolekcją" });
                if (result != null)
                {
                    using var stream = await result.OpenReadAsync();
                    using var reader = new System.IO.StreamReader(stream);
                    string text = await reader.ReadToEndAsync();

                    var imported = Models.Collection.Deserialize(text);

                    foreach (var col in imported.CustomColumns)
                        if (!_collection.CustomColumns.Contains(col)) _collection.CustomColumns.Add(col);

                    foreach (var item in imported.Items)
                        if (!_collection.Items.Any(i => i.Id == item.Id)) _collection.Items.Add(item);

                    App.SaveData();
                    RefreshData();
                    await DisplayAlert("Sukces", "Dane zostały zaimportowane i połączone.", "OK");
                }
#endif
            }
            catch (Exception ex)
            {
                await DisplayAlert("Błąd", $"Nie udało się zaimportować: {ex.Message}", "OK");
            }
        }
    }

    private async void OnItemSelected(object sender, SelectionChangedEventArgs e)
    {
        if (e.CurrentSelection.FirstOrDefault() is CollectionItem selectedItem)
        {
            ItemsList.SelectedItem = null;
            await Navigation.PushAsync(new ItemEditPage(_collection, selectedItem));
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using collectiblesManagementSystem.Models;

namespace collectiblesManagementSystem.Views;

public partial class ItemEditPage : ContentPage
{
    private readonly Collection _parentCollection;
    private readonly CollectionItem _currentItem;
    private readonly bool _isNew;

    public ItemEditPage(Collection parentCollection, CollectionItem itemToEdit = null)
    {
        InitializeComponent();

        _parentCollection = parentCollection;
        _isNew = itemToEdit == null;
        _currentItem = itemToEdit ?? new CollectionItem();

        if (!_isNew)
        {
            NameEntry.Text = _currentItem.Name;
            PriceEntry.Text = _currentItem.Price.ToString();
            StatusPicker.SelectedIndex = (int)_currentItem.Status;
            RatingSlider.Value = _currentItem.Rating;
            CommentEditor.Text = _currentItem.Comment;

            if (!string.IsNullOrEmpty(_currentItem.ImagePath))
                ItemImage.Source = ImageSource.FromFile(_currentItem.ImagePath);

            DeleteButton.IsVisible = true;
            Title = "Edytuj przedmiot";
        }
        else
        {
            Title = "Dodaj nowy przedmiot";
        }

        GenerateCustomColumns();
    }

    private Dictionary<string, Entry> _customEntries = new();

    private void GenerateCustomColumns()
    {
        CustomColumnsContainer.Children.Clear();
        _customEntries.Clear();

        foreach (var colName in _parentCollection.CustomColumns)
        {
            CustomColumnsContainer.Children.Add(new Label { Text = colName + ":", FontAttributes = FontAttributes.Bold });
            var entry = new Entry { Placeholder = "Wpisz wartość..." };
            if (_currentItem.CustomData.TryGetValue(colName, out var v))
                entry.Text = v;

            _customEntries[colName] = entry;
            CustomColumnsContainer.Children.Add(entry);
        }
    }

    private void OnRatingChanged(object sender, ValueChangedEventArgs e)
    {
        RatingLabel.Text = $"Ocena (zadowolenie): {(int)e.NewValue / 10}";
    }

    private async void OnSelectImageClicked(object sender, EventArgs e)
    {
        try
        {
            var result = await MediaPicker.Default.PickPhotoAsync();
            if (result != null)
            {
                _currentItem.ImagePath = result.FullPath;
                ItemImage.Source = ImageSource.FromFile(result.FullPath);
            }
        }
        catch (Exception)
        {
            await DisplayAlert("Błąd", "Nie udało się wczytać zdjęcia.", "OK");
        }
    }

    private async void OnSaveClicked(object sender, EventArgs e)
    {
        var name = NameEntry.Text?.Trim() ?? "";

        if (_isNew && _parentCollection.Items.Any(i => i.Name.Equals(name, StringComparison.OrdinalIgnoreCase)))
        {
            bool proceed = await DisplayAlert("Znaleziono duplikat",
                "Masz już przedmiot o takiej nazwie w tej kolekcji. Czy na pewno chcesz podać 2 raz taki sam element?",
                "Tak", "Anuluj");

            if (!proceed)
                return;
        }

        _currentItem.Name = name;
        if (double.TryParse(PriceEntry.Text, out double price))
            _currentItem.Price = price;

        _currentItem.Status = (ItemStatus)StatusPicker.SelectedIndex;
        _currentItem.Rating = (int)RatingSlider.Value;
        _currentItem.Comment = CommentEditor.Text ?? "";

        foreach (var kvp in _customEntries)
        {
            _currentItem.CustomData[kvp.Key] = kvp.Value.Text ?? "";
        }

        if (_isNew)
            _parentCollection.Items.Add(_currentItem);

        App.SaveData();

        await Navigation.PopAsync();
    }

    private async void OnDeleteClicked(object sender, EventArgs e)
    {
        bool answer = await DisplayAlert("Potwierdź", "Usunąć bezpowrotnie ten element?", "Tak", "Nie");
        if (answer)
        {
            _parentCollection.Items.Remove(_currentItem);
            App.SaveData();
            await Navigation.PopAsync();
        }
    }
}

